-- 02_reward_rules.sql
CREATE TABLE IF NOT EXISTS reward_rules (
    id                INTEGER PRIMARY KEY,
    payment_software  TEXT,
    payment_method    TEXT,
    user_level        TEXT,
    reward_rate       REAL,
    is_special        INTEGER DEFAULT 0,
    start_date        TEXT,
    end_date          TEXT,
    available_days    TEXT,
    rule_desc         TEXT,
    supported_stores  TEXT
);

